-- SQLite to PostgreSQL 迁移脚本
-- 生成时间: 2026-04-16

BEGIN;

CREATE TABLE IF NOT EXISTS chat_sessions (
    id VARCHAR(50),
    user_id INTEGER,
    title VARCHAR(200),
    messages JSON,
    created_at DATETIME DEFAULT 'CURRENT_TIMESTAMP',
    updated_at DATETIME DEFAULT 'CURRENT_TIMESTAMP',
    PRIMARY KEY (id)
);


CREATE TABLE IF NOT EXISTS dishes (
    id INTEGER,
    name VARCHAR(255),
    category VARCHAR(100),
    ingredients_quantified JSON,
    applicable_meals JSON,
    flavor VARCHAR(100),
    cost_per_serving FLOAT,
    nutrition JSON,
    tags JSON,
    PRIMARY KEY (id)
);


CREATE TABLE IF NOT EXISTS menu_histories (
    id VARCHAR(50),
    user_id INTEGER,
    name VARCHAR(100),
    menu_data JSON,
    metrics_data JSON,
    config_data JSON,
    created_at DATETIME DEFAULT 'CURRENT_TIMESTAMP',
    PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS standard_quotas (
    id INTEGER,
    class_type VARCHAR(50),
    quotas JSON,
    is_system BOOLEAN,
    name VARCHAR(100),
    description VARCHAR(500),
    quota_type VARCHAR(20),
    PRIMARY KEY (id)
);


CREATE TABLE IF NOT EXISTS users (
    id INTEGER,
    username VARCHAR(50),
    hashed_password VARCHAR(255),
    is_active BOOLEAN,
    role VARCHAR(20),
    created_at DATETIME DEFAULT 'CURRENT_TIMESTAMP',
    updated_at DATETIME,
    PRIMARY KEY (id)
);


COMMIT;
